from django.template import Template, Context

# Create a parent template with a for loop that includes a child template
parent_template = Template("""
{% for item in items %}
  {% include "child" only %}
{% endfor %}
""")

# Create a child template that tries to access forloop
from django.template import Engine

engine = Engine(debug=True)
engine.engine.template_loaders[0].engine.loaders[0]._template_cache = {
    'child': engine.from_string("forloop: {{ forloop }}")
}

try:
    result = parent_template.render(Context({'items': [1, 2, 3]}))
    print("Result:")
    print(result)
except Exception as e:
    print(f"Error: {e}")
EOF

