import os
import sys
import django
from django.conf import settings

# Configure Django settings
if not settings.configured:
    settings.configure(
        DEBUG=True,
        TEMPLATES=[{
            'BACKEND': 'django.template.backends.django.DjangoTemplates',
            'DIRS': [],
            'APP_DIRS': False,
            'OPTIONS': {
                'context_processors': [],
            },
        }],
    )
    django.setup()

from django.template import Template, Context, Engine

# Test case 1: forloop should NOT leak to isolated include
engine = Engine(debug=True, loaders=[
    ('django.template.loaders.locmem.Loader', {
        'parent': '{% for item in items %}{% include "child" only %}{% endfor %}',
        'child': 'forloop: {{ forloop.counter }}',
    }),
])

parent = engine.get_template('parent')
result = parent.render(Context({'items': [1, 2, 3]}))
print("Test 1 - forloop leak:")
print("Result:", repr(result))
if 'forloop' in result or '1' in result or '2' in result or '3' in result:
    print("BUG: forloop leaked into isolated include!")
else:
    print("OK: forloop properly isolated")

# Test case 2: Non-isolated include should still work
engine2 = Engine(debug=True, loaders=[
    ('django.template.loaders.locmem.Loader', {
        'parent2': '{% for item in items %}{% include "child2" %}{% endfor %}',
        'child2': 'item: {{ item }}, forloop: {{ forloop.counter }}',
    }),
])

parent2 = engine2.get_template('parent2')
result2 = parent2.render(Context({'items': [1, 2, 3]}))
print("\nTest 2 - non-isolated include:")
print("Result:", repr(result2))
if 'item: 1' in result2 and 'counter: 1' in result2:
    print("OK: non-isolated include works")
else:
    print("May be OK depending on output format")
